/// Provides a summary of the batch download plan.
#[derive(Debug)]
pub struct BatchDownloadPlan {
    pub file_count: usize,
    pub total_raw_size: u64,
    pub total_with_overhead: u64,
    pub largest_file: u64,
    pub smallest_file: u64,
    pub average_file_size: u64,
}

/// Creates a detailed batch download plan with validated sizes.
pub fn create_download_plan(
    file_sizes: &[u64],
    available_disk_space: u64,
) -> Result<BatchDownloadPlan, DownloadError> {
    let required_space = calculate_batch_download_size(file_sizes, available_disk_space)?;

    let total_raw = sum_file_sizes_checked(file_sizes)?;

    let largest = *file_sizes.iter().max().unwrap(); // safe: we checked non-empty
    let smallest = *file_sizes.iter().min().unwrap();
    let count = file_sizes.len() as u64;
    let average = total_raw / count;

    Ok(BatchDownloadPlan {
        file_count: file_sizes.len(),
        total_raw_size: total_raw,
        total_with_overhead: required_space,
        largest_file: largest,
        smallest_file: smallest,
        average_file_size: average,
    })
}

